UPDATE words SET meaning='걱정, 고민', example_zh='工作和生活的烦恼，找朋友聊聊就好多了。', example_ko='일과 생활의 고민은 친구한테 털어놓으면 훨씬 나아져.', example_pinyin='zhè cì kǎo shì de fàn wéi hěn guǎng ， yào duō fù xí 。' WHERE chinese='烦恼' AND pinyin='fán nǎo' AND hsk_level=4;
