UPDATE words SET meaning='기침하다', example_zh='我最近感冒了，一直在咳嗽。', example_ko='요즘 감기에 걸려서 계속 기침을 해.', example_pinyin='zhè lǐ de kōng qì hěn qīng xīn ， ràng rén gǎn jué xīn qíng shū chàng 。' WHERE chinese='咳嗽' AND pinyin='ké sou' AND hsk_level=4;
UPDATE words SET meaning='불쌍하다', example_zh='那只流浪狗太可怜了，我给了它一些食物。', example_ko='그 유기견이 너무 불쌍해서 먹을 것을 좀 줬어.', example_pinyin='kǒng pà jīn tiān lái bù liǎo ， wǒ lín shí yǒu shì 。' WHERE chinese='可怜' AND pinyin='kě lián' AND hsk_level=4;
UPDATE words SET meaning='하지만, 그러나', example_zh='他很努力，可是成绩还是不理想。', example_ko='그는 열심히 하는데 성적이 여전히 만족스럽지 않아.', example_pinyin='zhè duàn shí jiān gōng zuò tài kǔ le ， dàn chēng guò qù jiù hǎo le 。' WHERE chinese='可是' AND pinyin='kě shì' AND hsk_level=4;
UPDATE words SET meaning='아쉽다, 안타깝다', example_zh='可惜他没有参加这次比赛，不然肯定能赢。', example_ko='안타깝게도 그가 이번 대회에 참가하지 않았어, 아니었으면 틀림없이 이겼을 텐데.', example_pinyin='zhè tiáo lù hěn kuān ， liǎng liàng dà kǎ chē kě yǐ tóng shí tōng guò 。' WHERE chinese='可惜' AND pinyin='kě xī' AND hsk_level=4;
UPDATE words SET meaning='확실히, 틀림없이', example_zh='我肯定昨天把钥匙放在桌上了，怎么找不到？', example_ko='어제 분명히 열쇠를 책상 위에 뒀는데 왜 없지?', example_pinyin='kāi huì shí tā tài kùn le ， chà diǎn shuì zháo le 。' WHERE chinese='肯定' AND pinyin='kěn dìng' AND hsk_level=4;
UPDATE words SET meaning='자연, 자연스럽다', example_zh='这里的自然环境很好，空气非常清新。', example_ko='이곳의 자연환경이 좋아서 공기가 정말 맑아.', example_pinyin='chuàng yè chū qī fēi cháng kùn nán ， dàn tā jiān chí xià lái le 。' WHERE chinese='空气' AND pinyin='kōng qì' AND hsk_level=4;
UPDATE words SET meaning='아마도 ~일 것 같다 (우려)', example_zh='恐怕今天来不了，我临时有事。', example_ko='아마 오늘 못 올 것 같아, 갑자기 일이 생겼어.', example_pinyin='gōng sī jì huà kuò dà guī mó ， zēng jiā zhāo pìn rén shù 。' WHERE chinese='恐怕' AND pinyin='kǒng pà' AND hsk_level=4;
UPDATE words SET meaning='쓰다, 고생스럽다', example_zh='这段时间工作太苦了，但撑过去就好了。', example_ko='요즘 일이 너무 힘들지만 버티면 괜찮아질 거야.', example_pinyin='lā yī xià zhè gēn shéng zi ， mén jiù kāi le 。' WHERE chinese='苦' AND pinyin='kǔ' AND hsk_level=4;
UPDATE words SET meaning='넓다', example_zh='这条路很宽，可以并排走三辆车。', example_ko='이 길은 매우 넓어서 차 세 대가 나란히 다닐 수 있다.', example_pinyin='lā jī yào rēng jìn lā jī tǒng ， bù néng suí dì luàn rēng 。' WHERE chinese='宽' AND pinyin='kuān' AND hsk_level=4;
UPDATE words SET meaning='졸리다', example_zh='开会时他太困了，差点睡着了。', example_ko='회의할 때 너무 졸려서 하마터면 잠들 뻔했어.', example_pinyin='sì chuān cài fēi cháng là ， nǐ néng chī là ma ？' WHERE chinese='困' AND pinyin='kùn' AND hsk_level=4;
UPDATE words SET meaning='~하기만 하면', example_zh='只要你努力，什么困难都能克服。', example_ko='노력하기만 하면 어떤 어려움도 극복할 수 있어.', example_pinyin='lái bù jí jiě shì le ， gēn wǒ zǒu ba ！' WHERE chinese='困难' AND pinyin='kùn nan' AND hsk_level=4;
UPDATE words SET meaning='확대하다', example_zh='公司计划扩大规模，增加招聘人数。', example_ko='회사가 규모를 확대하고 채용 인원을 늘릴 계획이야.', example_pinyin='lí kāi chē hái yǒu èr shí fēn zhōng ， lái de jí de ， bié huāng 。' WHERE chinese='扩大' AND pinyin='kuò dà' AND hsk_level=4;
UPDATE words SET meaning='밀다', example_zh='门是推开的，不是拉开的，注意一下。', example_ko='문은 미는 거야, 당기는 게 아니야, 주의해.', example_pinyin='tā tài lǎn le ， zhōu mò zhěng tiān tǎng zài chuáng shàng shuā shǒu jī 。' WHERE chinese='拉' AND pinyin='lā' AND hsk_level=4;
UPDATE words SET meaning='쓰레기통', example_zh='垃圾要扔进垃圾桶，不能随地乱扔。', example_ko='쓰레기는 쓰레기통에 버려야 해, 아무 데나 버리면 안 돼.', example_pinyin='bú yào làng fèi shí wù ， chī duō shǎo ná duō shǎo 。' WHERE chinese='垃圾桶' AND pinyin='lā jī tǒng' AND hsk_level=4;
UPDATE words SET meaning='맵다', example_zh='四川菜非常辣，你能吃辣吗？', example_ko='쓰촨 요리는 정말 매워, 매운 거 먹을 수 있어?', example_pinyin='tā yòng zhú guāng wǎn cān qìng zhù jié hūn jì niàn rì ， hěn làng màn 。' WHERE chinese='辣' AND pinyin='là' AND hsk_level=4;
UPDATE words SET meaning='시간이 없다, 미처 ~못하다', example_zh='来不及解释了，跟我走吧！', example_ko='설명할 시간 없어, 나랑 같이 가!', example_pinyin='lǎo hǔ shì sēn lín zhōng de wáng zhě ， shì zuì wēi xiǎn de dòng wù zhī yī 。' WHERE chinese='来不及' AND pinyin='lái bu jí' AND hsk_level=4;
UPDATE words SET meaning='시간이 충분하다, 늦지 않았다', example_zh='离开车还有二十分钟，来得及的，别慌。', example_ko='기차 출발까지 20분 남았어, 시간 충분해, 당황하지 마.', example_pinyin='yù dào wēi xiǎn yào lěng jìng chǔ lǐ ， bú yào huāng luàn 。' WHERE chinese='来得及' AND pinyin='lái de jí' AND hsk_level=4;
UPDATE words SET meaning='게으르다', example_zh='他太懒了，周末整天躺在床上刷手机。', example_ko='그는 너무 게을러서 주말에 하루 종일 침대에 누워 핸드폰만 봐.', example_pinyin='tā hěn yǒu lǐ mào ， měi cì jiàn dào zhǎng bèi dū huì zhǔ dòng dǎ zhāo hū 。' WHERE chinese='懒' AND pinyin='lǎn' AND hsk_level=4;
UPDATE words SET meaning='낭비하다', example_zh='不要浪费食物，吃多少拿多少。', example_ko='음식 낭비하지 마, 먹을 만큼만 가져가.', example_pinyin='wǒ tóu fà zhǎng le ， gāi qù lǐ fà le 。' WHERE chinese='浪费' AND pinyin='làng fèi' AND hsk_level=4;
UPDATE words SET meaning='낭만적이다, 로맨틱하다', example_zh='他用烛光晚餐庆祝结婚纪念日，很浪漫。', example_ko='그는 결혼 기념일을 촛불 만찬으로 기념했는데 정말 로맨틱했어.', example_pinyin='zhè dào tí de jiě tí sī lù wǒ zhōng yú lǐ jiě le 。' WHERE chinese='浪漫' AND pinyin='làng màn' AND hsk_level=4;
UPDATE words SET meaning='호랑이', example_zh='老虎是森林中的王者，是最危险的动物之一。', example_ko='호랑이는 숲의 왕으로 가장 위험한 동물 중 하나야.', example_pinyin='tā de lǐ xiǎng shì qù guó wài shēn zào ， chéng wéi yī míng xué zhě 。' WHERE chinese='老虎' AND pinyin='lǎo hǔ' AND hsk_level=4;
UPDATE words SET meaning='단점', example_zh='他的缺点是有时候太冲动，不够冷静。', example_ko='그의 단점은 가끔 너무 충동적이고 충분히 침착하지 않다는 거야.', example_pinyin='tā zhōng wén shuō dé tài lì hài le ， gēn mǔ yǔ zhě yī yàng liú lì 。' WHERE chinese='冷静' AND pinyin='lěng jìng' AND hsk_level=4;
UPDATE words SET meaning='예의, 예절', example_zh='他很有礼貌，每次见到长辈都会主动打招呼。', example_ko='그는 예의가 바르고 어른을 만날 때마다 먼저 인사를 해.', example_pinyin='bān le yī tiān de dōng xī ， lì qì yòng wán le ， lèi jí le 。' WHERE chinese='礼貌' AND pinyin='lǐ mào' AND hsk_level=4;
UPDATE words SET meaning='이발하다', example_zh='我头发长了，该去理发了。', example_ko='머리카락이 길어졌어, 이발하러 가야겠다.', example_pinyin='nǐ kě yǐ duō zuò yī xiē tǐ yù yùn dòng ， lì rú pǎo bù 、 yóu yǒng děng 。' WHERE chinese='理发' AND pinyin='lǐ fà' AND hsk_level=4;
UPDATE words SET meaning='예습하다', example_zh='提前预习新课的内容，上课会更容易理解。', example_ko='미리 새 수업 내용을 예습하면 수업 시간에 이해하기 더 쉬워.', example_pinyin='tā máng dé lián chī fàn de shí jiān dōu méi yǒu 。' WHERE chinese='理解' AND pinyin='lǐ jiě' AND hsk_level=4;
UPDATE words SET meaning='실제, 현실', example_zh='理想很美好，但实际情况可能不一样。', example_ko='이상은 아름답지만 실제 상황은 다를 수 있어.', example_pinyin='wǒ hěn jiǔ méi yǒu hé tā lián xì le ， bù zhī dào tā jìn kuàng zěn yàng 。' WHERE chinese='理想' AND pinyin='lǐ xiǎng' AND hsk_level=4;
UPDATE words SET meaning='대단하다, 굉장하다', example_zh='他中文说得太厉害了，跟母语者一样流利。', example_ko='그는 중국어를 엄청 잘해서 원어민만큼 유창해.', example_pinyin='bàng wǎn fēng chuī lái ， liáng kuài duō le ， kě yǐ chū qù sàn bù le 。' WHERE chinese='厉害' AND pinyin='lì hai' AND hsk_level=4;
UPDATE words SET meaning='힘, 기력', example_zh='搬了一天的东西，力气用完了，累极了。', example_ko='하루 종일 짐을 옮겼더니 기력이 다 빠져서 너무 피곤해.', example_pinyin='huàn le xīn dēng pào ， fáng jiān dùn shí liàng le hěn duō 。' WHERE chinese='力气' AND pinyin='lì qi' AND hsk_level=4;
UPDATE words SET meaning='예를 들면', example_zh='你可以多做一些体育运动，例如跑步、游泳等。', example_ko='체육 운동을 좀 더 해도 좋아, 예를 들면 달리기, 수영 같은 거.', example_pinyin='wǒ men zài kā fēi diàn liáo tiān liáo le sān gè xiǎo shí 。' WHERE chinese='例如' AND pinyin='lì rú' AND hsk_level=4;
UPDATE words SET meaning='두 사람, 두 개', example_zh='我们俩是好朋友，认识已经十年了。', example_ko='우리 둘은 친한 친구로 알고 지낸 지 벌써 10년이 됐다.', example_pinyin='chú le zhōng wén ， tā lìng wài hái huì shuō yīng yǔ hé rì yǔ 。' WHERE chinese='俩' AND pinyin='liǎ' AND hsk_level=4;
