UPDATE words SET meaning='시원하다 (기온)', example_zh='傍晚风吹来，凉快多了，可以出去散步了。', example_ko='저녁에 바람이 부니까 시원해져서 산책하러 나갈 수 있겠다.', example_pinyin='diàn yǐng jié wěi tài gǎn rén le ， wǒ rěn bú zhù liú lèi le 。' WHERE chinese='凉快' AND pinyin='liáng kuai' AND hsk_level=4;
UPDATE words SET meaning='둥글다', example_zh='月亮圆圆的，今晚是满月。', example_ko='달이 둥글고, 오늘 밤은 보름달이야.', example_pinyin='tā yīng yǔ shuō dé fēi cháng liú lì ， zài wài qǐ gōng zuò méi wèn tí 。' WHERE chinese='亮' AND pinyin='liàng' AND hsk_level=4;
