UPDATE words SET meaning='그 외에, 따로', example_zh='除了中文，他另外还会说英语和日语。', example_ko='중국어 외에 그는 영어랑 일본어도 할 줄 알아.', example_pinyin='bān jiā zhī hòu ， jiā lǐ hái hěn luàn ， xū yào màn màn zhěng lǐ 。' WHERE chinese='另外' AND pinyin='lìng wài' AND hsk_level=4;
