UPDATE words SET meaning='눈물을 흘리다', example_zh='电影结尾太感人了，我忍不住流泪了。', example_ko='영화 결말이 너무 감동적이어서 나 참지 못하고 눈물을 흘렸어.', example_pinyin='zuò shì bù néng mǎ hǔ ， yào rèn zhēn duì dài měi yí gè xì jié 。' WHERE chinese='流泪' AND pinyin='liú lèi' AND hsk_level=4;
