UPDATE words SET meaning='유행하다', example_zh='这首歌最近很流行，到处都能听到。', example_ko='이 노래가 요즘 정말 유행해서 어디서든 들려.', example_pinyin='xǐ wán zǎo jì de yòng gān jìng de máo jīn cā gàn shēn tǐ 。' WHERE chinese='流行' AND pinyin='liú xíng' AND hsk_level=4;
