UPDATE words SET meaning='변호사', example_zh='他遇到了法律问题，找了一位律师帮忙处理。', example_ko='그는 법률 문제가 생겨서 변호사를 찾아서 처리를 부탁했어.', example_pinyin='wǒ zuó wǎn zuò le yí gè hěn qí guài de mèng ， dōu jì bù qīng chǔ le 。' WHERE chinese='律师' AND pinyin='lǜ shī' AND hsk_level=4;
UPDATE words SET meaning='번거롭다, 귀찮다', example_zh='这件事很麻烦，处理起来需要花很多时间。', example_ko='이 일은 번거로워서 처리하는 데 시간이 많이 걸려.', example_pinyin='shǒu jī de mì mǎ yào shè zhì dé fù zá yī xiē ， bǎo hù gè rén xìn xī 。' WHERE chinese='麻烦' AND pinyin='má fan' AND hsk_level=4;
UPDATE words SET meaning='대충하다, 허술하다', example_zh='做事不能马虎，要认真对待每一个细节。', example_ko='일을 대충 하면 안 돼, 모든 세부 사항을 성실하게 대해야 해.', example_pinyin='zhè ge APP miǎn fèi xià zài ， bù xū yào fù fèi 。' WHERE chinese='马虎' AND pinyin='mǎ hu' AND hsk_level=4;
UPDATE words SET meaning='둥글다', example_zh='月亮圆圆的，今晚是满月。', example_ko='달이 둥글고, 오늘 밤은 보름달이야.', example_pinyin='zhōng guó shì yí gè duō mín zú de guó jiā ， yǒu wǔ shí liù gè mín zú 。' WHERE chinese='满' AND pinyin='mǎn' AND hsk_level=4;
