UPDATE words SET meaning='민족', example_zh='中国是一个多民族的国家，有五十六个民族。', example_ko='중국은 다민족 국가로 56개 민족이 있어.', example_pinyin='xiāng zi nèi yǒu jǐ jiàn yī fú hé yī xiē líng shí 。' WHERE chinese='民族' AND pinyin='mín zú' AND hsk_level=4;
