UPDATE words SET meaning='느긋하다, 편하다', example_zh='假期里，我喜欢轻松地在家看书、喝茶。', example_ko='휴가 때 나는 집에서 느긋하게 책 읽고 차 마시는 걸 좋아해.', example_pinyin='kuài dì dào le ， nǐ qù kuài dì diǎn qǔ yī xià bāo guǒ 。' WHERE chinese='轻松' AND pinyin='qīng sōng' AND hsk_level=4;
