UPDATE words SET meaning='마음대로, 아무거나', example_zh='今天我请客，大家随便点，不用客气。', example_ko='오늘 내가 쏠게, 다들 마음대로 시켜, 사양하지 마.', example_pinyin='zhè dào cài quē shǎo yán ， zài jiā yì diǎn 。' WHERE chinese='请客' AND pinyin='qǐng kè' AND hsk_level=4;
UPDATE words SET meaning='가난하다', example_zh='他家境很穷，但靠自己努力考上了大学。', example_ko='그는 가난한 집안 출신이지만 스스로 노력해서 대학에 합격했어.', example_pinyin='tā kàn qǐ lái hěn yán sù ， shuō huà què hěn yōu mò 。' WHERE chinese='穷' AND pinyin='qióng' AND hsk_level=4;
