UPDATE words SET meaning='장점', example_zh='每个人都有自己的优点和缺点。', example_ko='모든 사람은 자신만의 장점과 단점이 있어.', example_pinyin='guò nián de shí hòu ， jiē shàng hěn rè nào ， dào chù fàng biān pào 。' WHERE chinese='缺点' AND pinyin='quē diǎn' AND hsk_level=4;
