UPDATE words SET meaning='수입, 소득', example_zh='他换了新工作，收入比以前高了很多。', example_ko='그가 새 직장으로 바꾸고 나서 수입이 예전보다 많이 올랐어.', example_pinyin='shòu huò yuán rè qíng dì xiàng wǒ jiè shào le zhè kuǎn shǒu jī de tè diǎn 。' WHERE chinese='收入' AND pinyin='shōu rù' AND hsk_level=4;
