UPDATE words SET meaning='빈칸 채우기', example_zh='这道填空题很难，我不知道应该填什么。', example_ko='이 빈칸 채우기 문제 너무 어려워서 뭘 써야 할지 모르겠어.', example_pinyin='mén shì tuī kāi de ， bú shì lā kāi de ， zhù yì yī xià 。' WHERE chinese='填空' AND pinyin='tián kòng' AND hsk_level=4;
UPDATE words SET meaning='조건, 상황', example_zh='这份工作的条件很好，薪资高、福利也好。', example_ko='이 직장 조건이 좋아, 연봉도 높고 복지도 좋아.', example_pinyin='yóu yú xià yǔ ， yùn dòng huì tuī chí dào xià zhōu jǔ xíng 。' WHERE chinese='条件' AND pinyin='tiáo jiàn' AND hsk_level=4;
UPDATE words SET meaning='멈추다, 중단하다', example_zh='下雨了，他停止了跑步，回家了。', example_ko='비가 오자 그는 달리기를 멈추고 집으로 돌아갔어.', example_pinyin='jìn mén qián qǐng tuō xié ， xiè xiè pèi hé 。' WHERE chinese='停止' AND pinyin='tíng zhǐ' AND hsk_level=4;
