UPDATE words SET meaning='넓다', example_zh='这条路很宽，两辆大卡车可以同时通过。', example_ko='이 도로 폭이 넓어서 큰 트럭 두 대가 동시에 지나갈 수 있어.', example_pinyin='tā shuō de huà wǒ wán quán tīng bù dǒng ， kě néng shì fāng yán 。' WHERE chinese='通过' AND pinyin='tōng guò' AND hsk_level=4;
