UPDATE words SET meaning='양말', example_zh='出门前检查一下，袜子有没有穿反。', example_ko='나가기 전에 양말 뒤집어 신지 않았는지 확인해봐.', example_pinyin='zhè dào cài wèi dào hěn tè bié ， wǒ yǐ qián méi yǒu chī guò 。' WHERE chinese='袜子' AND pinyin='wà zi' AND hsk_level=4;
UPDATE words SET meaning='반대이다', example_zh='他的想法和我的完全相反，我们总是争论。', example_ko='그의 생각이 나와 완전히 반대라서 우리는 항상 논쟁해.', example_pinyin='jīn tiān wēn dù bǐ zuó tiān dī le wǔ dù ， jì de duō chuān diǎn 。' WHERE chinese='完全' AND pinyin='wán quán' AND hsk_level=4;
