UPDATE words SET meaning='종종, 자주', example_zh='他往往在深夜才开始工作，这是他的习惯。', example_ko='그는 종종 한밤중이 되어서야 일을 시작하는데, 그게 그의 습관이야.', example_pinyin='liǎng guó lǐng dǎo rén wò shǒu ， biǎo shì yǒu hǎo hé zuò 。' WHERE chinese='往往' AND pinyin='wǎng wǎng' AND hsk_level=4;
UPDATE words SET meaning='테니스', example_zh='她每周打两次网球，身材一直保持得很好。', example_ko='그녀는 매주 두 번 테니스를 쳐서 몸매를 항상 잘 유지해.', example_pinyin='gōng chǎng pái chū de fèi shuǐ wū rǎn le fù jìn de hé liú 。' WHERE chinese='网球' AND pinyin='wǎng qiú' AND hsk_level=4;
