UPDATE words SET meaning='맛, 냄새', example_zh='这道菜味道很特别，我以前没有吃过。', example_ko='이 요리 맛이 정말 독특해서 전에 먹어본 적이 없어.', example_pinyin='tā wù huì le wǒ de yì si ， qí shí wǒ bú shì nà ge yì si 。' WHERE chinese='味道' AND pinyin='wèi dao' AND hsk_level=4;
UPDATE words SET meaning='온도', example_zh='今天温度比昨天低了五度，记得多穿点。', example_ko='오늘 온도가 어제보다 5도 낮아졌으니 옷 더 입는 거 잊지 마.', example_pinyin='xī hóng shì chǎo jī dàn shì zhōng guó jiā cháng cài lǐ zuì cháng jiàn de yī dào 。' WHERE chinese='温度' AND pinyin='wēn dù' AND hsk_level=4;
