UPDATE words SET meaning='신용카드', example_zh='现在很多地方都可以用信用卡付款，很方便。', example_ko='요즘 많은 곳에서 신용카드로 결제할 수 있어서 편해.', example_pinyin='tā shòu shāng le ， liú le hěn duō xuè ， xū yào lì kè jiù yī 。' WHERE chinese='信用卡' AND pinyin='xìn yòng kǎ' AND hsk_level=4;
