UPDATE words SET meaning='성별', example_zh='这份表格需要填写姓名、年龄和性别。', example_ko='이 양식에는 이름, 나이, 성별을 기입해야 해.', example_pinyin='ya ， nǐ de tóu fà jiǎn le ！ hǎo kàn duō le ！' WHERE chinese='性别' AND pinyin='xìng bié' AND hsk_level=4;
