UPDATE words SET meaning='행복하다', example_zh='家人健康平安，就是最大的幸福。', example_ko='가족이 건강하고 평안한 것이 가장 큰 행복이야.', example_pinyin='tā de lǎo shī yāo qiú hěn yán gé ， dàn jiào chū lái de xué shēng dōu hěn yōu xiù 。' WHERE chinese='幸福' AND pinyin='xìng fú' AND hsk_level=4;
