UPDATE words SET meaning='많은', example_zh='图书馆里有许多关于历史的书籍。', example_ko='도서관에 역사 관련 서적이 많아.', example_pinyin='tā kǎo shàng le běi jīng dà xué de yán jiū shēng ， jiā rén dōu hěn gāo xìng 。' WHERE chinese='许多' AND pinyin='xǔ duō' AND hsk_level=4;
