UPDATE words SET meaning='심각하다', example_zh='这次洪水造成了严重的财产损失。', example_ko='이번 홍수로 심각한 재산 손실이 발생했어.', example_pinyin='tā hái méi dào ， yě xǔ lù shàng dǔ chē le ba 。' WHERE chinese='严重' AND pinyin='yán zhòng' AND hsk_level=4;
