UPDATE words SET meaning='인상', example_zh='她给我留下了非常好的第一印象。', example_ko='그녀는 나한테 정말 좋은 첫인상을 남겼어.', example_pinyin='tā chí dào le ， yú shì cuò guò le kāi chǎng 。' WHERE chinese='印象' AND pinyin='yìn xiàng' AND hsk_level=4;
