UPDATE words SET meaning='즐겁다', example_zh='这次旅行非常愉快，希望下次还能一起去。', example_ko='이번 여행이 정말 즐거웠어, 다음에도 같이 갔으면 좋겠어.', example_pinyin='wǒ zàn shí zhù zài péng yǒu jiā ， děng zhǎo dào fáng zi zài bān guò qù 。' WHERE chinese='愉快' AND pinyin='yú kuài' AND hsk_level=4;
