UPDATE words SET meaning='~뿐만 아니라', example_zh='他不但会说中文，还会说日语。', example_ko='그는 중국어를 할 줄 알 뿐만 아니라 일본어도 할 줄 알아.', example_pinyin='zhè ge tuán duì yóu wǔ míng chéng yuán zǔ chéng ， gè yǒu fēn gōng 。' WHERE chinese='中文' AND pinyin='Zhōng wén' AND hsk_level=4;
UPDATE words SET meaning='중점, 핵심', example_zh='学习的重点是理解，不是死记硬背。', example_ko='공부의 중점은 이해하는 거야, 무조건 외우는 게 아니야.', example_pinyin='xué xiào zǔ zhī tóng xué qù cān guān bó wù guǎn 。' WHERE chinese='重点' AND pinyin='zhòng diǎn' AND hsk_level=4;
UPDATE words SET meaning='중시하다, 중요하게 여기다', example_zh='公司非常重视员工的身体健康。', example_ko='회사는 직원들의 건강을 매우 중시해.', example_pinyin='chī dōng xī de shí hòu bié zhāng zhe zuǐ ， zhè yàng bù lǐ mào 。' WHERE chinese='重视' AND pinyin='zhòng shì' AND hsk_level=4;
UPDATE words SET meaning='주변, 주위', example_zh='他周围的朋友都是很有能力的人。', example_ko='그의 주변 친구들은 모두 능력 있는 사람들이야.', example_pinyin='nǐ zuì hǎo zǎo diǎn chū fā ， lù shàng kě néng dǔ chē 。' WHERE chinese='周围' AND pinyin='zhōu wéi' AND hsk_level=4;
UPDATE words SET meaning='돼지', example_zh='农场里养了很多猪，每天要喂食两次。', example_ko='농장에는 돼지가 많이 있는데 매일 두 번씩 먹이를 줘야 한다.', example_pinyin='zuì hòu ， gǎn xiè dà jiā de cān yù hé zhī chí ！' WHERE chinese='猪' AND pinyin='zhū' AND hsk_level=4;
UPDATE words SET meaning='점차, 서서히', example_zh='他的身体逐渐好转，很快就能出院了。', example_ko='그의 몸 상태가 점차 좋아져서 곧 퇴원할 수 있을 것 같아.', example_pinyin='wǒ men yào zūn zhòng bié rén de yì jiàn ， bù néng qiáng xíng shuō fú 。' WHERE chinese='逐渐' AND pinyin='zhú jiàn' AND hsk_level=4;
UPDATE words SET meaning='자발적으로, 먼저', example_zh='他很主动，总是第一个来帮忙。', example_ko='그는 아주 적극적이어서 항상 제일 먼저 나서서 도와줘.', example_pinyin='tā cí zhí hòu kāi shǐ zuò shēng yì ， xiàn zài jīng yíng yī jiā cān tīng 。' WHERE chinese='主动' AND pinyin='zhǔ dòng' AND hsk_level=4;
UPDATE words SET meaning='아이디어, 생각', example_zh='你有什么好主意，说来听听。', example_ko='좋은 아이디어 있으면 말해봐.', example_pinyin='qián miàn nà zuò dà lóu shì wǒ men gōng sī de xīn bàn gōng lóu 。' WHERE chinese='主意' AND pinyin='zhǔ yi' AND hsk_level=4;
UPDATE words SET meaning='축하하다', example_zh='大家一起来祝贺她顺利完成论文！', example_ko='다 같이 그녀의 논문 완성을 축하해요!', example_pinyin='zhè jié chē xiāng de zuò wèi yǐ jīng quán mǎn le ， qǐng qù xià yī jié 。' WHERE chinese='祝贺' AND pinyin='zhù hè' AND hsk_level=4;
