UPDATE words SET meaning='전문적으로, 특별히', example_zh='他专门学过厨艺，做的菜特别好吃。', example_ko='그는 요리를 전문적으로 배워서 음식이 정말 맛있어.', example_pinyin='tā zhuān mén xué guò chú yì ， zuò de cài tè bié hǎo chī 。' WHERE chinese='专门' AND pinyin='zhuān mén' AND hsk_level=4;
UPDATE words SET meaning='전공, 전문적이다', example_zh='她的专业是计算机，毕业后很容易找工作。', example_ko='그녀의 전공은 컴퓨터라서 졸업 후에 취업이 쉬워.', example_pinyin='tā de zhuān yè shì jì suàn jī ， bì yè hòu hěn róng yì zhǎo gōng zuò 。' WHERE chinese='专业' AND pinyin='zhuān yè' AND hsk_level=4;
UPDATE words SET meaning='돈을 벌다', example_zh='他在上海做生意，赚了不少钱。', example_ko='그는 상하이에서 사업을 해서 돈을 꽤 벌었어.', example_pinyin='tā zài shàng hǎi zuò shēng yì ， zhuàn le bù shǎo qián 。' WHERE chinese='赚' AND pinyin='zhuàn' AND hsk_level=4;
