UPDATE words SET meaning='꼼꼼하다, 자세히', example_zh='做题的时候要仔细，不要粗心大意。', example_ko='문제 풀 때 꼼꼼하게 해야 해, 실수하면 안 돼.', example_pinyin='zuò tí de shí hòu yào zǐ xì ， bú yào cū xīn dà yì 。' WHERE chinese='仔细' AND pinyin='zǐ xì' AND hsk_level=4;
