UPDATE words SET meaning='조직하다, 구성하다', example_zh='她负责组织这次活动，安排得井井有条。', example_ko='그녀가 이번 행사를 조직 담당인데 아주 체계적으로 준비했어.', example_pinyin='tā fù zé zǔ zhī zhè cì huó dòng ， ān pái dé jǐng jǐng yǒu tiáo 。' WHERE chinese='组织' AND pinyin='zǔ zhī' AND hsk_level=4;
UPDATE words SET meaning='입', example_zh='他嘴上说没事，但表情看起来不太好。', example_ko='그는 입으로는 괜찮다고 했지만 표정은 별로 안 좋아 보였어.', example_pinyin='tā zuǐ shàng shuō méi shì ， dàn biǎo qíng kàn qǐ lái bù tài hǎo 。' WHERE chinese='嘴' AND pinyin='zuǐ' AND hsk_level=4;
