UPDATE words SET meaning='존중하다', example_zh='我们应该尊重每个人的选择和想法。', example_ko='우리는 모든 사람의 선택과 생각을 존중해야 해.', example_pinyin='wǒ men yīng gāi zūn zhòng měi gè rén de xuǎn zé hé xiǎng fǎ 。' WHERE chinese='尊重' AND pinyin='zūn zhòng' AND hsk_level=4;
UPDATE words SET meaning='장사하다, 사업하다', example_zh='他辞职以后开始做生意，现在过得不错。', example_ko='그는 퇴직한 후 사업을 시작했는데 지금은 잘 지내고 있어.', example_pinyin='tā cí zhí yǐ hòu kāi shǐ zuò shēng yì ， xiàn zài guò dé bù cuò 。' WHERE chinese='做生意' AND pinyin='zuò shēng yì' AND hsk_level=4;
