UPDATE words SET meaning='작가, 저자', example_zh='这本书的作者很有名，他写过很多小说。', example_ko='이 책의 작가는 유명한데 소설을 많이 썼어.', example_pinyin='zhè běn shū de zuò zhě hěn yǒu míng ， tā xiě guò hěn duō xiǎo shuō 。' WHERE chinese='作者' AND pinyin='zuò zhě' AND hsk_level=4;
